const iconPool = [
  { name: "Docker", icon: DockerIcon },
  { name: "Next.js", icon: NextjsIcon },
  { name: "GitLab", icon: GitlabIcon },
  { name: "MySQL", icon: MysqlIcon },
  { name: "AWS", icon: AwsIcon },
  { name: "MongoDB", icon: MongodbIcon },
  { name: "PostgreSQL", icon: PostgresIcon },
  { name: "Vercel", icon: VercelIcon },
  { name: "Claude", icon: ClaudeIcon },
  { name: "Figma", icon: FigmaIcon },
  { name: "OpenAI", icon: OpenaiIcon },
  { name: "Firebase", icon: FirebaseIcon },
];

type TileData = {
  row: number;
  col: number;
  hasLogo: boolean;
  slotKey: string;
};

// Coordinate mapping to approximate the "scattered" look in the image.
const tiles: TileData[] = [
  // Row 0
  { row: 0, col: 1, hasLogo: false, slotKey: "0_1" },
  { row: 0, col: 3, hasLogo: true, slotKey: "0_3" },

  // Row 1
  { row: 1, col: 0, hasLogo: false, slotKey: "1_0" },
  { row: 1, col: 2, hasLogo: true, slotKey: "1_2" },
  { row: 1, col: 4, hasLogo: true, slotKey: "1_4" },

  // Row 2
  { row: 2, col: 1, hasLogo: true, slotKey: "2_1" },
  { row: 2, col: 3, hasLogo: true, slotKey: "2_3" },

  // Row 3
  { row: 3, col: 0, hasLogo: false, slotKey: "3_0" },
  { row: 3, col: 2, hasLogo: true, slotKey: "3_2" },
  { row: 3, col: 4, hasLogo: true, slotKey: "3_4" },

  // Row 4
  { row: 4, col: 1, hasLogo: true, slotKey: "4_1" },
  { row: 4, col: 3, hasLogo: true, slotKey: "4_3" },
];

const slotKeys = ["0_3", "1_2", "1_4", "2_1", "2_3", "3_2", "3_4", "4_1", "4_3"];

export function Integrations() {
  // Initialize grid slots 0-8 with distinct indices from the pool (0 to 8)
  const [activeIcons, setActiveIcons] = useState<Record<string, number>>({
    "0_3": 0,
    "1_2": 1,
    "1_4": 2,
    "2_1": 3,
    "2_3": 4,
    "3_2": 5,
    "3_4": 6,
    "4_1": 7,
    "4_3": 8,
  });

  // Cycle all logo slots simultaneously using standard array shuffling.
  useEffect(() => {
    const interval = setInterval(() => {
      const indices = Array.from({ length: iconPool.length }, (_, i) => i);
      
      // Shuffle the index list (Fisher-Yates shuffle)
      for (let i = indices.length - 1; i > 0; i--) {
        const j = Math.floor(Math.random() * (i + 1));
        [indices[i], indices[j]] = [indices[j], indices[i]];
      }

      // Slice the first 9 unique items
      const selected = indices.slice(0, 9);

      const nextActive: Record<string, number> = {};
      slotKeys.forEach((key, idx) => {
        nextActive[key] = selected[idx];
      });

      setActiveIcons(nextActive);
    }, 4500); // Trigger auto-swap of all items every 4.5 seconds

    return () => clearInterval(interval);
  }, []);

  return (
    <div className="mx-auto grid max-w-5xl grid-cols-1 gap-12 p-4 md:grid-cols-2 md:items-center">
      {/* Left Content */}
      <div className="max-w-xl space-y-4 text-left">
        <h2 className="text-3xl md:text-4xl font-bold tracking-tight text-text-light-primary font-heading">
          Technologies We Use
        </h2>
        <p className="text-sm md:text-base text-text-light-secondary leading-relaxed">
          We build our applications using a modern tech stack and integrate
          seamlessly with over 100+ industry-leading tools, frameworks, and cloud
          infrastructure platforms to streamline your workflow and scale your business.
        </p>
      </div>

      {/* Right Content - Visual Grid */}
      <div className="place-items-end flex justify-center md:justify-end">
        <div className="mask-[radial-gradient(ellipse_at_center,black,black,transparent)] relative w-[360px] h-[360px]">
          {tiles.map((tile) => (
            <IntegrationCard
              key={tile.slotKey}
              row={tile.row}
              col={tile.col}
              activeIconIndex={tile.hasLogo ? activeIcons[tile.slotKey] : undefined}
            />
          ))}
        </div>
      </div>
    </div>
  );
}

function IntegrationCard({
  row,
  col,
  activeIconIndex,
}: {
  row: number;
  col: number;
  activeIconIndex?: number;
}) {
  const IconComponent = activeIconIndex !== undefined ? iconPool[activeIconIndex]?.icon : null;
  const name = activeIconIndex !== undefined ? iconPool[activeIconIndex]?.name : "";

  return (
    <div
      className={cn(
        "absolute flex w-[72px] h-[72px] items-center justify-center rounded-xl border border-border-light/80 transition-all duration-300 hover:scale-105 hover:border-accent-orange/30 overflow-hidden",
        activeIconIndex !== undefined
          ? "bg-white shadow-xs dark:bg-card/60"
          : "bg-secondary/10 dark:bg-background"
      )}
      style={{
        left: col * 72,
        top: row * 72,
      }}
    >
      <AnimatePresence mode="wait">
        {IconComponent ? (
          <motion.div
            key={activeIconIndex}
            initial={{ opacity: 0, scale: 0.8 }}
            animate={{ opacity: 1, scale: 1 }}
            exit={{ opacity: 0, scale: 0.8 }}
            transition={{ duration: 0.4 }}
            className="flex items-center justify-center w-full h-full p-3.5 cursor-pointer text-text-light-primary"
            title={name}
          >
            <IconComponent className="w-full h-full object-contain" />
          </motion.div>
        ) : null}
      </AnimatePresence>
    </div>
  );
}
